import { MAX_AGENT_STEPS_DEFAULT } from '@siya/common/constants/agents'
import { SiyaClient, loadLocalAgents } from '@siya/sdk'

import { TelegramEventAdapter } from './event-adapter'
import { extractTextFromAgentOutput } from '../telegram/format'
import {
  loadTelegramSession,
  saveTelegramSession,
} from '../session/session-store'
import { setActiveTelegramChat } from '../telegram/outbound'
import {
  createTelegramNotifyTools,
  injectTelegramToolsIntoAgents,
} from '../tools/telegram-notify-tools'

import type { AgentDefinition, MessageContent } from '@siya/sdk'
import type { Logger } from '@siya/common/types/contracts/logger'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'
import type { RunState } from '@siya/sdk'

export type SiyaBridgeOptions = {
  apiKey: string
  cwd: string
  telegramConfig: TelegramChannelConfig
  agentDefinitions?: AgentDefinition[]
  logger?: Logger
}

export type ProcessMessageResult = {
  reply: string
  runState: RunState
}

const defaultLogger: Logger = {
  debug: () => {},
  info: (_data, msg) => {
    if (msg) console.log(msg)
  },
  warn: (_data, msg) => {
    console.warn(msg ?? _data)
  },
  error: (_data, msg) => {
    console.error(msg ?? _data)
  },
}

export class SiyaBridge {
  private client: SiyaClient
  private agentId: string
  private agentDefinitions: AgentDefinition[]
  private logger: Logger
  private telegramTools: ReturnType<typeof createTelegramNotifyTools>
  private adapters = new Map<string, TelegramEventAdapter>()

  constructor(options: SiyaBridgeOptions) {
    this.agentId = options.telegramConfig.defaultAgent
    this.telegramTools = createTelegramNotifyTools({ cwd: options.cwd })
    this.agentDefinitions = injectTelegramToolsIntoAgents(
      options.agentDefinitions ?? [],
      [this.agentId, 'base2', 'base2-max', 'base2-lite', 'base2-fast'],
    )
    this.logger = options.logger ?? defaultLogger

    this.client = new SiyaClient({
      apiKey: options.apiKey,
      cwd: options.cwd,
      agentDefinitions: this.agentDefinitions,
      customToolDefinitions: this.telegramTools,
      logger: this.logger,
      overrideTools: {
        ask_user: async () => [
          {
            type: 'json',
            value: { skipped: true, answers: [] },
          },
        ],
      },
    })
  }

  static async create(options: SiyaBridgeOptions): Promise<SiyaBridge> {
    let agentDefinitions = options.agentDefinitions
    if (!agentDefinitions || agentDefinitions.length === 0) {
      const loaded = await loadLocalAgents({ verbose: false })
      agentDefinitions = Object.values(loaded)
    }
    return new SiyaBridge({ ...options, agentDefinitions })
  }

  private getAdapter(chatId: string): TelegramEventAdapter {
    let adapter = this.adapters.get(chatId)
    if (!adapter) {
      adapter = new TelegramEventAdapter()
      this.adapters.set(chatId, adapter)
    }
    return adapter
  }

  async processMessage(params: {
    chatId: string
    text: string
    content?: MessageContent[]
    signal?: AbortSignal
  }): Promise<ProcessMessageResult> {
    const { chatId, text, content, signal } = params
    const adapter = this.getAdapter(chatId)
    adapter.resetStream(chatId)
    setActiveTelegramChat(chatId)

    const session = await loadTelegramSession(chatId)

    const runState = await this.client.run({
      agent: this.agentId,
      prompt: text,
      content,
      customToolDefinitions: this.telegramTools,
      previousRun: session?.runState ?? undefined,
      maxAgentSteps: MAX_AGENT_STEPS_DEFAULT,
      signal,
      handleEvent: (event) => adapter.onEvent(chatId, event),
      handleStreamChunk: (chunk) => adapter.onChunk(chatId, chunk as string),
    })

    try {
      await saveTelegramSession({
        chatId,
        runState,
        updatedAt: Date.now(),
      })
    } catch (error) {
      this.logger.warn(
        { error: error instanceof Error ? error.message : String(error) },
        'Failed to persist Telegram session (agent reply still sent)',
      )
    }

    const streamed = adapter.getStreamText(chatId).trim()
    const agentText =
      streamed || extractTextFromAgentOutput(runState.output)
    const reply = adapter.getDisplayText(chatId, agentText)

    return { reply, runState }
  }

  getStreamingText(chatId: string): string {
    return this.getAdapter(chatId).getDisplayText(chatId)
  }

  getDisplayText(chatId: string, finalText?: string): string {
    return this.getAdapter(chatId).getDisplayText(chatId, finalText)
  }

  shouldStreamEdit(chatId: string): boolean {
    return this.getAdapter(chatId).shouldEdit(chatId)
  }

  markStreamEdited(chatId: string): void {
    this.getAdapter(chatId).markEdited(chatId)
  }
}

export async function createGatewayBridge(
  options: SiyaBridgeOptions,
): Promise<SiyaBridge> {
  return SiyaBridge.create(options)
}

import { Bot } from 'grammy'
import { run } from '@grammyjs/runner'

import { registerTelegramHandlers } from './handlers'
import { registerTelegramOutbound, unregisterTelegramOutbound } from './outbound'

import type { SiyaBridge } from '../bridge/siya-bridge'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'

export type TelegramBotHandle = {
  stop: () => Promise<void>
  botUsername?: string
}

export async function startTelegramBot(params: {
  token: string
  config: TelegramChannelConfig
  bridge: SiyaBridge
  projectCwd: string
}): Promise<TelegramBotHandle> {
  const bot = new Bot(params.token)
  const me = await bot.api.getMe()

  registerTelegramOutbound({
    api: bot.api,
    config: params.config,
  })

  registerTelegramHandlers(bot, {
    bridge: params.bridge,
    config: params.config,
    botUsername: me.username,
    botToken: params.token,
    projectCwd: params.projectCwd,
  })

  const runner = run(bot, {
    runner: {
      fetch: {
        allowed_updates: ['message'],
      },
    },
  })

  return {
    botUsername: me.username,
    stop: async () => {
      await runner.stop()
      unregisterTelegramOutbound()
    },
  }
}

import {
  checkGroupMessageAccess,
  isBotMentioned,
  isGroupChatType,
  isOwnerUser,
} from '../security/group-access'
import { chunkTelegramMessage, escapeHtml } from './format'
import { extractMediaFromMessage } from './media'

import type { Bot, Context } from 'grammy'
import type { SiyaBridge } from '../bridge/siya-bridge'
import type { MessageContent } from '@siya/sdk'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'

const activeRuns = new Map<string, AbortController>()

export type TelegramHandlerDeps = {
  bridge: SiyaBridge
  config: TelegramChannelConfig
  botUsername?: string
  botToken: string
  projectCwd: string
}

async function sendLongReply(ctx: Context, text: string): Promise<void> {
  const chunks = chunkTelegramMessage(text)
  for (const chunk of chunks) {
    await ctx.reply(chunk)
  }
}

async function processAgentMessage(
  ctx: Context,
  deps: TelegramHandlerDeps,
  params: { promptText: string; content?: MessageContent[] },
): Promise<void> {
  const { bridge, config } = deps
  const { promptText, content } = params
  const chatId = String(ctx.chat?.id ?? ctx.from?.id)

  if (promptText === '/start') {
    await ctx.reply(
      'Siya Telegram gateway is connected.\n\n' +
        'Send text, screenshots, or image files.\n' +
        'I can also message you proactively on Telegram when needed.\n' +
        (isGroupChatType(ctx.chat?.type)
          ? 'In groups, mention me with @' +
            (deps.botUsername ?? 'siya') +
            ' in your caption or message.'
          : 'Tool calls are shown live while the agent works.'),
    )
    return
  }

  if (promptText === '/chatid' || promptText === '/groupid') {
    await ctx.reply(
      `Chat ID: ${chatId}\nUser ID: ${ctx.from?.id}\nType: ${ctx.chat?.type ?? 'unknown'}`,
    )
    return
  }

  const existing = activeRuns.get(chatId)
  if (existing) {
    existing.abort()
  }

  const controller = new AbortController()
  activeRuns.set(chatId, controller)

  const hasMedia = Boolean(content?.some((part) => part.type === 'image'))
  const statusMessage = await ctx.reply(
    hasMedia ? 'Analyzing image…' : 'Thinking…',
  )

  try {
    const streamMessageId = statusMessage.message_id
    const streamEnabled = config.streaming === 'partial'

    const runPromise = bridge.processMessage({
      chatId,
      text: promptText,
      content,
      signal: controller.signal,
    })

    const pushLiveUpdate = async () => {
      const display = bridge.getStreamingText(chatId).trim()
      if (!display || !bridge.shouldStreamEdit(chatId)) {
        return
      }
      try {
        await ctx.api.editMessageText(
          chatId,
          streamMessageId,
          display.slice(0, 4000),
        )
        bridge.markStreamEdited(chatId)
      } catch {
        // Ignore edit rate limits
      }
    }

    if (streamEnabled) {
      const interval = setInterval(() => {
        void pushLiveUpdate()
      }, 900)

      try {
        const result = await runPromise
        clearInterval(interval)
        const finalText = result.reply.trim() || 'Done.'
        try {
          await ctx.api.editMessageText(
            chatId,
            streamMessageId,
            finalText.slice(0, 4000),
          )
        } catch {
          await sendLongReply(ctx, finalText)
        }
      } catch (error) {
        clearInterval(interval)
        throw error
      }
    } else {
      const interval = setInterval(() => {
        void pushLiveUpdate()
      }, 900)

      try {
        const result = await runPromise
        clearInterval(interval)
        const finalText = result.reply.trim() || 'Done.'
        try {
          await ctx.api.editMessageText(
            chatId,
            streamMessageId,
            finalText.slice(0, 4000),
          )
        } catch {
          await sendLongReply(ctx, finalText)
        }
      } catch (error) {
        clearInterval(interval)
        throw error
      }
    }
  } catch (error) {
    if (controller.signal.aborted) {
      await ctx.api.editMessageText(
        chatId,
        statusMessage.message_id,
        'Cancelled.',
      )
      return
    }

    const message =
      error instanceof Error ? error.message : 'An unexpected error occurred.'
    await ctx.api.editMessageText(
      chatId,
      statusMessage.message_id,
      `Error: ${escapeHtml(message)}`,
      { parse_mode: 'HTML' },
    )
  } finally {
    activeRuns.delete(chatId)
  }
}

function checkAccessForText(
  ctx: Context,
  deps: TelegramHandlerDeps,
  text: string,
): { allowed: boolean; cleanedText?: string } {
  const user = ctx.from
  if (!user) {
    return { allowed: false }
  }

  const chatId = String(ctx.chat?.id ?? user.id)
  const senderUserId = String(user.id)
  const isGroup = isGroupChatType(ctx.chat?.type)

  if (isGroup) {
    return checkGroupMessageAccess({
      config: deps.config,
      chatId,
      senderUserId,
      text,
      entities: ctx.message?.caption
        ? ctx.message.entities
        : ctx.message?.entities,
      botUsername: deps.botUsername,
    })
  }

  if (!isOwnerUser(deps.config, senderUserId)) {
    return { allowed: false }
  }

  return { allowed: true, cleanedText: text }
}

async function handleIncomingMessage(
  ctx: Context,
  deps: TelegramHandlerDeps,
  options: { text: string; content?: MessageContent[] },
): Promise<void> {
  const access = checkAccessForText(ctx, deps, options.text)
  if (!access.allowed) {
    return
  }

  const promptText = access.cleanedText ?? options.text
  await processAgentMessage(ctx, deps, {
    promptText,
    content: options.content,
  })
}

export function registerTelegramHandlers(
  bot: Bot,
  deps: TelegramHandlerDeps,
): void {
  bot.on('message:text', async (ctx) => {
    const text = ctx.message?.text?.trim()
    if (!text) {
      return
    }

    await handleIncomingMessage(ctx, deps, { text })
  })

  bot.on('message:photo', async (ctx) => {
    const caption = ctx.message?.caption?.trim() ?? ''
    const isGroup = isGroupChatType(ctx.chat?.type)

    if (isGroup) {
      if (
        !caption ||
        !isBotMentioned({
          text: caption,
          entities: ctx.message?.caption_entities,
          botUsername: deps.botUsername,
          mentionAliases: deps.config.mentionAliases,
        })
      ) {
        return
      }
    }

    const access = checkAccessForText(
      ctx,
      deps,
      isGroup ? caption : caption || 'Analyze this screenshot.',
    )
    if (!access.allowed) {
      return
    }

    try {
      const media = await extractMediaFromMessage({
        ctx,
        botToken: deps.botToken,
        projectCwd: deps.projectCwd,
        fallbackPrompt: access.cleanedText ?? 'Analyze this screenshot.',
      })

      await processAgentMessage(ctx, deps, {
        promptText: media.promptText,
        content: media.content.length > 0 ? media.content : undefined,
      })
    } catch (error) {
      const message =
        error instanceof Error ? error.message : 'Failed to process image.'
      await ctx.reply(`Error: ${message}`)
    }
  })

  bot.on('message:document', async (ctx) => {
    const caption = ctx.message?.caption?.trim() ?? ''
    const isGroup = isGroupChatType(ctx.chat?.type)

    if (isGroup) {
      if (
        !caption ||
        !isBotMentioned({
          text: caption,
          entities: ctx.message?.caption_entities,
          botUsername: deps.botUsername,
          mentionAliases: deps.config.mentionAliases,
        })
      ) {
        return
      }
    }

    const access = checkAccessForText(
      ctx,
      deps,
      isGroup ? caption : caption || 'Analyze this file.',
    )
    if (!access.allowed) {
      return
    }

    try {
      const media = await extractMediaFromMessage({
        ctx,
        botToken: deps.botToken,
        projectCwd: deps.projectCwd,
        fallbackPrompt: access.cleanedText ?? 'Analyze this file.',
      })

      await processAgentMessage(ctx, deps, {
        promptText: media.promptText,
        content: media.content.length > 0 ? media.content : undefined,
      })
    } catch (error) {
      const message =
        error instanceof Error ? error.message : 'Failed to process file.'
      await ctx.reply(`Error: ${message}`)
    }
  })
}

