export type StartGatewayOptions = {
  cwd?: string
  apiKey: string
  agentDefinitions?: AgentDefinition[]
  logger?: Logger
  /** foreground = standalone `siya gateway`; embedded = alongside main CLI */
  mode?: 'foreground' | 'embedded'
}

export type GatewayHandle = {
  stop: () => Promise<void>
}

export async function startGateway(
  options: StartGatewayOptions,
): Promise<GatewayHandle> {
  const cwd = options.cwd ?? process.cwd()
  const config = await loadGatewayConfig({ cwd, verbose: true })

  const telegram = config.channels.telegram
  if (!telegram?.enabled) {
    throw new Error(
      'Telegram channel is not enabled. Run `siya gateway setup` first.',
    )
  }

  if (!telegram.botToken) {
    throw new Error(
      'Telegram bot token missing. Set TELEGRAM_BOT_TOKEN or channels.telegram.botToken in gateway.json.',
    )
  }

  const projectCwd = telegram.cwd ? telegram.cwd : cwd
  const bridge = await SiyaBridge.create({
    apiKey: options.apiKey,
    cwd: projectCwd,
    telegramConfig: telegram,
    agentDefinitions: options.agentDefinitions,
    logger: options.logger,
  })

  const health = await startHealthServer(config.gateway.port)
  const bot = await startTelegramBot({
    token: telegram.botToken,
    config: telegram,
    bridge,
    projectCwd,
  })

  const mode = options.mode ?? 'foreground'
  const log = (message: string) => {
    if (mode === 'embedded') {
      options.logger?.info({}, message)
    } else {
      console.log(message)
    }
  }

  log(
    `Siya Telegram gateway started (agent=${telegram.defaultAgent}, cwd=${projectCwd}, bot=@${bot.botUsername ?? 'unknown'})`,
  )
  log(`Health: http://127.0.0.1:${config.gateway.port}/health`)
  if (mode === 'foreground') {
    console.log('Press Ctrl+C to stop.')
  }

  return {
    stop: async () => {
      await bot.stop()
      await health.close()
    },
  }
}

export async function getGatewayStatus(options?: {
  cwd?: string
}): Promise<{
  configured: boolean
  sourceFile?: string
  telegramEnabled: boolean
  hasToken: boolean
  defaultAgent?: string
  projectCwd?: string
}> {
  const config = await loadGatewayConfig({
    cwd: options?.cwd ?? process.cwd(),
    verbose: false,
  })

  const telegram = config.channels.telegram
  return {
    configured: Boolean(config._sourceFilePath),
    sourceFile: config._sourceFilePath || undefined,
    telegramEnabled: Boolean(telegram?.enabled),
    hasToken: Boolean(telegram?.botToken),
    defaultAgent: telegram?.defaultAgent,
    projectCwd: telegram?.cwd,
  }
}

import { MAX_AGENT_STEPS_DEFAULT } from '@siya/common/constants/agents'
import { SiyaClient, loadLocalAgents } from '@siya/sdk'

import { TelegramEventAdapter } from './event-adapter'
import { extractTextFromAgentOutput } from '../telegram/format'
import {
  loadTelegramSession,
  saveTelegramSession,
} from '../session/session-store'
import { setActiveTelegramChat } from '../telegram/outbound'
import {
  createTelegramNotifyTools,
  injectTelegramToolsIntoAgents,
} from '../tools/telegram-notify-tools'

import type { AgentDefinition, MessageContent } from '@siya/sdk'
import type { Logger } from '@siya/common/types/contracts/logger'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'
import type { RunState } from '@siya/sdk'

export type SiyaBridgeOptions = {
  apiKey: string
  cwd: string
  telegramConfig: TelegramChannelConfig
  agentDefinitions?: AgentDefinition[]
  logger?: Logger
}

export type ProcessMessageResult = {
  reply: string
  runState: RunState
}

const defaultLogger: Logger = {
  debug: () => {},
  info: (_data, msg) => {
    if (msg) console.log(msg)
  },
  warn: (_data, msg) => {
    console.warn(msg ?? _data)
  },
  error: (_data, msg) => {
    console.error(msg ?? _data)
  },
}

export class SiyaBridge {
  private client: SiyaClient
  private agentId: string
  private agentDefinitions: AgentDefinition[]
  private logger: Logger
  private telegramTools: ReturnType<typeof createTelegramNotifyTools>
  private adapters = new Map<string, TelegramEventAdapter>()

  constructor(options: SiyaBridgeOptions) {
    this.agentId = options.telegramConfig.defaultAgent
    this.telegramTools = createTelegramNotifyTools({ cwd: options.cwd })
    this.agentDefinitions = injectTelegramToolsIntoAgents(
      options.agentDefinitions ?? [],
      [this.agentId, 'base2', 'base2-max', 'base2-lite', 'base2-fast'],
    )
    this.logger = options.logger ?? defaultLogger

    this.client = new SiyaClient({
      apiKey: options.apiKey,
      cwd: options.cwd,
      agentDefinitions: this.agentDefinitions,
      customToolDefinitions: this.telegramTools,
      logger: this.logger,
      overrideTools: {
        ask_user: async () => [
          {
            type: 'json',
            value: { skipped: true, answers: [] },
          },
        ],
      },
    })
  }

  static async create(options: SiyaBridgeOptions): Promise<SiyaBridge> {
    let agentDefinitions = options.agentDefinitions
    if (!agentDefinitions || agentDefinitions.length === 0) {
      const loaded = await loadLocalAgents({ verbose: false })
      agentDefinitions = Object.values(loaded)
    }
    return new SiyaBridge({ ...options, agentDefinitions })
  }

  private getAdapter(chatId: string): TelegramEventAdapter {
    let adapter = this.adapters.get(chatId)
    if (!adapter) {
      adapter = new TelegramEventAdapter()
      this.adapters.set(chatId, adapter)
    }
    return adapter
  }

  async processMessage(params: {
    chatId: string
    text: string
    content?: MessageContent[]
    signal?: AbortSignal
  }): Promise<ProcessMessageResult> {
    const { chatId, text, content, signal } = params
    const adapter = this.getAdapter(chatId)
    adapter.resetStream(chatId)
    setActiveTelegramChat(chatId)

    const session = await loadTelegramSession(chatId)

    const runState = await this.client.run({
      agent: this.agentId,
      prompt: text,
      content,
      customToolDefinitions: this.telegramTools,
      previousRun: session?.runState ?? undefined,
      maxAgentSteps: MAX_AGENT_STEPS_DEFAULT,
      signal,
      handleEvent: (event) => adapter.onEvent(chatId, event),
      handleStreamChunk: (chunk) => adapter.onChunk(chatId, chunk as string),
    })

    try {
      await saveTelegramSession({
        chatId,
        runState,
        updatedAt: Date.now(),
      })
    } catch (error) {
      this.logger.warn(
        { error: error instanceof Error ? error.message : String(error) },
        'Failed to persist Telegram session (agent reply still sent)',
      )
    }

    const streamed = adapter.getStreamText(chatId).trim()
    const agentText =
      streamed || extractTextFromAgentOutput(runState.output)
    const reply = adapter.getDisplayText(chatId, agentText)

    return { reply, runState }
  }

  getStreamingText(chatId: string): string {
    return this.getAdapter(chatId).getDisplayText(chatId)
  }

  getDisplayText(chatId: string, finalText?: string): string {
    return this.getAdapter(chatId).getDisplayText(chatId, finalText)
  }

  shouldStreamEdit(chatId: string): boolean {
    return this.getAdapter(chatId).shouldEdit(chatId)
  }

  markStreamEdited(chatId: string): void {
    this.getAdapter(chatId).markEdited(chatId)
  }
}

export async function createGatewayBridge(
  options: SiyaBridgeOptions,
): Promise<SiyaBridge> {
  return SiyaBridge.create(options)
}

import { Bot } from 'grammy'
import { run } from '@grammyjs/runner'

import { registerTelegramHandlers } from './handlers'
import { registerTelegramOutbound, unregisterTelegramOutbound } from './outbound'

import type { SiyaBridge } from '../bridge/siya-bridge'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'

export type TelegramBotHandle = {
  stop: () => Promise<void>
  botUsername?: string
}

export async function startTelegramBot(params: {
  token: string
  config: TelegramChannelConfig
  bridge: SiyaBridge
  projectCwd: string
}): Promise<TelegramBotHandle> {
  const bot = new Bot(params.token)
  const me = await bot.api.getMe()

  registerTelegramOutbound({
    api: bot.api,
    config: params.config,
  })

  registerTelegramHandlers(bot, {
    bridge: params.bridge,
    config: params.config,
    botUsername: me.username,
    botToken: params.token,
    projectCwd: params.projectCwd,
  })

  const runner = run(bot, {
    runner: {
      fetch: {
        allowed_updates: ['message'],
      },
    },
  })

  return {
    botUsername: me.username,
    stop: async () => {
      await runner.stop()
      unregisterTelegramOutbound()
    },
  }
}

import {
  checkGroupMessageAccess,
  isBotMentioned,
  isGroupChatType,
  isOwnerUser,
} from '../security/group-access'
import { chunkTelegramMessage, escapeHtml } from './format'
import { extractMediaFromMessage } from './media'

import type { Bot, Context } from 'grammy'
import type { SiyaBridge } from '../bridge/siya-bridge'
import type { MessageContent } from '@siya/sdk'
import type { TelegramChannelConfig } from '@siya/common/types/gateway'

const activeRuns = new Map<string, AbortController>()

export type TelegramHandlerDeps = {
  bridge: SiyaBridge
  config: TelegramChannelConfig
  botUsername?: string
  botToken: string
  projectCwd: string
}

async function sendLongReply(ctx: Context, text: string): Promise<void> {
  const chunks = chunkTelegramMessage(text)
  for (const chunk of chunks) {
    await ctx.reply(chunk)
  }
}

async function processAgentMessage(
  ctx: Context,
  deps: TelegramHandlerDeps,
  params: { promptText: string; content?: MessageContent[] },
): Promise<void> {
  const { bridge, config } = deps
  const { promptText, content } = params
  const chatId = String(ctx.chat?.id ?? ctx.from?.id)

  if (promptText === '/start') {
    await ctx.reply(
      'Siya Telegram gateway is connected.\n\n' +
        'Send text, screenshots, or image files.\n' +
        'I can also message you proactively on Telegram when needed.\n' +
        (isGroupChatType(ctx.chat?.type)
          ? 'In groups, mention me with @' +
            (deps.botUsername ?? 'siya') +
            ' in your caption or message.'
          : 'Tool calls are shown live while the agent works.'),
    )
    return
  }

  if (promptText === '/chatid' || promptText === '/groupid') {
    await ctx.reply(
      `Chat ID: ${chatId}\nUser ID: ${ctx.from?.id}\nType: ${ctx.chat?.type ?? 'unknown'}`,
    )
    return
  }

  const existing = activeRuns.get(chatId)
  if (existing) {
    existing.abort()
  }

  const controller = new AbortController()
  activeRuns.set(chatId, controller)

  const hasMedia = Boolean(content?.some((part) => part.type === 'image'))
  const statusMessage = await ctx.reply(
    hasMedia ? 'Analyzing image…' : 'Thinking…',
  )

  try {
    const streamMessageId = statusMessage.message_id
    const streamEnabled = config.streaming === 'partial'

    const runPromise = bridge.processMessage({
      chatId,
      text: promptText,
      content,
      signal: controller.signal,
    })

    const pushLiveUpdate = async () => {
      const display = bridge.getStreamingText(chatId).trim()
      if (!display || !bridge.shouldStreamEdit(chatId)) {
        return
      }
      try {
        await ctx.api.editMessageText(
          chatId,
          streamMessageId,
          display.slice(0, 4000),
        )
        bridge.markStreamEdited(chatId)
      } catch {
        // Ignore edit rate limits
      }
    }

    if (streamEnabled) {
      const interval = setInterval(() => {
        void pushLiveUpdate()
      }, 900)

      try {
        const result = await runPromise
        clearInterval(interval)
        const finalText = result.reply.trim() || 'Done.'
        try {
          await ctx.api.editMessageText(
            chatId,
            streamMessageId,
            finalText.slice(0, 4000),
          )
        } catch {
          await sendLongReply(ctx, finalText)
        }
      } catch (error) {
        clearInterval(interval)
        throw error
      }
    } else {
      const interval = setInterval(() => {
        void pushLiveUpdate()
      }, 900)

      try {
        const result = await runPromise
        clearInterval(interval)
        const finalText = result.reply.trim() || 'Done.'
        try {
          await ctx.api.editMessageText(
            chatId,
            streamMessageId,
            finalText.slice(0, 4000),
          )
        } catch {
          await sendLongReply(ctx, finalText)
        }
      } catch (error) {
        clearInterval(interval)
        throw error
      }
    }
  } catch (error) {
    if (controller.signal.aborted) {
      await ctx.api.editMessageText(
        chatId,
        statusMessage.message_id,
        'Cancelled.',
      )
      return
    }

    const message =
      error instanceof Error ? error.message : 'An unexpected error occurred.'
    await ctx.api.editMessageText(
      chatId,
      statusMessage.message_id,
      `Error: ${escapeHtml(message)}`,
      { parse_mode: 'HTML' },
    )
  } finally {
    activeRuns.delete(chatId)
  }
}

function checkAccessForText(
  ctx: Context,
  deps: TelegramHandlerDeps,
  text: string,
): { allowed: boolean; cleanedText?: string } {
  const user = ctx.from
  if (!user) {
    return { allowed: false }
  }

  const chatId = String(ctx.chat?.id ?? user.id)
  const senderUserId = String(user.id)
  const isGroup = isGroupChatType(ctx.chat?.type)

  if (isGroup) {
    return checkGroupMessageAccess({
      config: deps.config,
      chatId,
      senderUserId,
      text,
      entities: ctx.message?.caption
        ? ctx.message.entities
        : ctx.message?.entities,
      botUsername: deps.botUsername,
    })
  }

  if (!isOwnerUser(deps.config, senderUserId)) {
    return { allowed: false }
  }

  return { allowed: true, cleanedText: text }
}

async function handleIncomingMessage(
  ctx: Context,
  deps: TelegramHandlerDeps,
  options: { text: string; content?: MessageContent[] },
): Promise<void> {
  const access = checkAccessForText(ctx, deps, options.text)
  if (!access.allowed) {
    return
  }

  const promptText = access.cleanedText ?? options.text
  await processAgentMessage(ctx, deps, {
    promptText,
    content: options.content,
  })
}

export function registerTelegramHandlers(
  bot: Bot,
  deps: TelegramHandlerDeps,
): void {
  bot.on('message:text', async (ctx) => {
    const text = ctx.message?.text?.trim()
    if (!text) {
      return
    }

    await handleIncomingMessage(ctx, deps, { text })
  })

  bot.on('message:photo', async (ctx) => {
    const caption = ctx.message?.caption?.trim() ?? ''
    const isGroup = isGroupChatType(ctx.chat?.type)

    if (isGroup) {
      if (
        !caption ||
        !isBotMentioned({
          text: caption,
          entities: ctx.message?.caption_entities,
          botUsername: deps.botUsername,
          mentionAliases: deps.config.mentionAliases,
        })
      ) {
        return
      }
    }

    const access = checkAccessForText(
      ctx,
      deps,
      isGroup ? caption : caption || 'Analyze this screenshot.',
    )
    if (!access.allowed) {
      return
    }

    try {
      const media = await extractMediaFromMessage({
        ctx,
        botToken: deps.botToken,
        projectCwd: deps.projectCwd,
        fallbackPrompt: access.cleanedText ?? 'Analyze this screenshot.',
      })

      await processAgentMessage(ctx, deps, {
        promptText: media.promptText,
        content: media.content.length > 0 ? media.content : undefined,
      })
    } catch (error) {
      const message =
        error instanceof Error ? error.message : 'Failed to process image.'
      await ctx.reply(`Error: ${message}`)
    }
  })

  bot.on('message:document', async (ctx) => {
    const caption = ctx.message?.caption?.trim() ?? ''
    const isGroup = isGroupChatType(ctx.chat?.type)

    if (isGroup) {
      if (
        !caption ||
        !isBotMentioned({
          text: caption,
          entities: ctx.message?.caption_entities,
          botUsername: deps.botUsername,
          mentionAliases: deps.config.mentionAliases,
        })
      ) {
        return
      }
    }

    const access = checkAccessForText(
      ctx,
      deps,
      isGroup ? caption : caption || 'Analyze this file.',
    )
    if (!access.allowed) {
      return
    }

    try {
      const media = await extractMediaFromMessage({
        ctx,
        botToken: deps.botToken,
        projectCwd: deps.projectCwd,
        fallbackPrompt: access.cleanedText ?? 'Analyze this file.',
      })

      await processAgentMessage(ctx, deps, {
        promptText: media.promptText,
        content: media.content.length > 0 ? media.content : undefined,
      })
    } catch (error) {
      const message =
        error instanceof Error ? error.message : 'Failed to process file.'
      await ctx.reply(`Error: ${message}`)
    }
  })
}

/**
 * Union type of all available tool names
 */
export type ToolName =
  | 'add_message'
  | 'apply_patch'
  | 'ask_user'
  | 'code_search'
  | 'end_turn'
  | 'find_files'
  | 'glob'
  | 'gravity_index'
  | 'list_directory'
  | 'lookup_agent_info'
  | 'propose_str_replace'
  | 'propose_write_file'
  | 'read_docs'
  | 'read_files'
  | 'read_subtree'
  | 'read_url'
  | 'render_ui'
  | 'run_file_change_hooks'
  | 'run_terminal_command'
  | 'set_messages'
  | 'set_output'
  | 'skill'
  | 'spawn_agents'
  | 'str_replace'
  | 'suggest_followups'
  | 'task_completed'
  | 'think_deeply'
  | 'web_search'
  | 'write_file'
  | 'write_todos'

/**
 * Map of tool names to their parameter types
 */
export interface ToolParamsMap {
  add_message: AddMessageParams
  apply_patch: ApplyPatchParams
  ask_user: AskUserParams
  code_search: CodeSearchParams
  end_turn: EndTurnParams
  find_files: FindFilesParams
  glob: GlobParams
  gravity_index: GravityIndexParams
  list_directory: ListDirectoryParams
  lookup_agent_info: LookupAgentInfoParams
  propose_str_replace: ProposeStrReplaceParams
  propose_write_file: ProposeWriteFileParams
  read_docs: ReadDocsParams
  read_files: ReadFilesParams
  read_subtree: ReadSubtreeParams
  read_url: ReadUrlParams
  render_ui: RenderUiParams
  run_file_change_hooks: RunFileChangeHooksParams
  run_terminal_command: RunTerminalCommandParams
  set_messages: SetMessagesParams
  set_output: SetOutputParams
  skill: SkillParams
  spawn_agents: SpawnAgentsParams
  str_replace: StrReplaceParams
  suggest_followups: SuggestFollowupsParams
  task_completed: TaskCompletedParams
  think_deeply: ThinkDeeplyParams
  web_search: WebSearchParams
  write_file: WriteFileParams
  write_todos: WriteTodosParams
}

/**
 * Add a new message to the conversation history. To be used for complex requests that can't be solved in a single step, as you may forget what happened!
 */
export interface AddMessageParams {
  role: 'user' | 'assistant'
  content: string
}

/**
 * Apply a file operation (create, update, or delete) using Codex-style apply_patch format.
 */
export interface ApplyPatchParams {
  /** The file operation to perform. */
  operation: {
    /** Operation type: create_file, update_file, or delete_file */
    type: 'create_file' | 'update_file' | 'delete_file'
    /** File path relative to project root */
    path: string
    /** Diff content. Required for create_file and update_file. Lines prefixed with + for creates, unified diff with @@ hunks for updates. */
    diff?: string
  }
}

/**
 * Ask the user multiple choice questions and pause execution until they respond.
 */
export interface AskUserParams {
  /** List of multiple choice questions to ask the user */
  questions: {
    /** The question to ask the user */
    question: string
    /** Short label (max 12 chars) displayed as a chip/tag */
    header?: string
    /** Array of answer options with label and optional description (minimum 2) */
    options: {
      /** The display text for this option */
      label: string
      /** Explanation shown when option is focused */
      description?: string
    }[]
    /** If true, allows selecting multiple options (checkbox). If false, single selection only (radio). */
    multiSelect?: boolean
    /** Validation rules for "Other" text input */
    validation?: {
      /** Maximum length for "Other" text input */
      maxLength?: number
      /** Minimum length for "Other" text input */
      minLength?: number
      /** Regex pattern for "Other" text input */
      pattern?: string
      /** Custom error message when pattern fails */
      patternError?: string
    }
  }[]
}

/**
 * Search for string patterns in the project's files. This tool uses ripgrep (rg), a fast line-oriented search tool. Use this tool only when read_files is not sufficient to find the files you need.
 */
export interface CodeSearchParams {
  /** The pattern to search for. */
  pattern: string
  /** Optional ripgrep flags to customize the search (e.g., "-i" for case-insensitive, "-g *.ts -g *.js" for TypeScript and JavaScript files only, "-g !*.test.ts" to exclude Typescript test files,  "-A 3" for 3 lines after match, "-B 2" for 2 lines before match). */
  flags?: string
  /** Optional working directory to search within, relative to the project root. Defaults to searching the entire project. */
  cwd?: string
  /** Maximum number of results to return per file. Defaults to 15. There is also a global limit of 250 results across all files. */
  maxResults?: number
}

/**
 * End your turn, regardless of any new tool results that might be coming. This will allow the user to type another prompt.
 */
export interface EndTurnParams {}

/**
 * Find several files related to a brief natural language description of the files or the name of a function or class you are looking for.
 */
export interface FindFilesParams {
  /** A brief natural language description of the files or the name of a function or class you are looking for. It's also helpful to mention a directory or two to look within. */
  prompt: string
}

/**
 * Search for files matching a glob pattern. Returns matching file paths sorted by modification time.
 */
export interface GlobParams {
  /** Glob pattern to match files against (e.g., *.js, src/glob/*.ts, glob/test/glob/*.go). */
  pattern: string
  /** Optional working directory to search within, relative to project root. If not provided, searches from project root. */
  cwd?: string
}

/**
 * Use the Gravity Index tool discovery and install API.
 */
export interface GravityIndexParams {
  /** Which Gravity Index operation to perform. search: recommend a provider; browse: list catalog services; list_categories: list categories with counts; get_service: full detail for a known slug; report_integration: report a completed integration. */
  action:
    | 'search'
    | 'browse'
    | 'list_categories'
    | 'get_service'
    | 'report_integration'
  /** For action "search": what the user needs, including stack, constraints, and required capabilities. */
  query?: string
  /** For action "search": continue a previous search. For action "report_integration": the search_id from the earlier search result (required). */
  search_id?: string
  /** For action "search": optional structured JSON context about the project, stack, or constraints. */
  context?: Record<string, any>
  /** For action "browse": optional category filter, e.g. Database, Auth, Payments, Hosting, Email, AI. */
  category?: string
  /** For action "browse": optional keyword filter, e.g. sendgrid or postgres. */
  q?: string
  /** For action "get_service": service slug, e.g. supabase, stripe, sendgrid (required). */
  slug?: string
  /** For action "report_integration": slug of the service that was actually integrated (required). */
  integrated_slug?: string
}

/**
 * List files and directories in the specified path. Returns separate arrays of file names and directory names.
 */
export interface ListDirectoryParams {
  /** Directory path to list, relative to the project root. */
  path: string
}

/**
 * Retrieve information about an agent by ID
 */
export interface LookupAgentInfoParams {
  /** Agent ID (short local or full published format) */
  agentId: string
}

/**
 * Propose string replacements in a file without actually applying them.
 */
export interface ProposeStrReplaceParams {
  /** The path to the file to edit. */
  path: string
  /** Array of replacements to make. */
  replacements: {
    /** The string to replace. This must be an *exact match* of the string you want to replace, including whitespace and punctuation. */
    oldString: string
    /** The string to replace the corresponding oldString with. Can be empty to delete. */
    newString: string
    /** Whether to allow multiple replacements of oldString. */
    allowMultiple?: boolean
  }[]
}

/**
 * Propose creating or editing a file without actually applying the changes.
 */
export interface ProposeWriteFileParams {
  /** Path to the file relative to the **project root** */
  path: string
  /** What the change is intended to do in only one sentence. */
  instructions: string
  /** Edit snippet to apply to the file. */
  content: string
}

/**
 * Fetch up-to-date documentation for libraries and frameworks using Context7 API.
 */
export interface ReadDocsParams {
  /** The library or framework name (e.g., "Next.js", "MongoDB", "React"). Use the official name as it appears in documentation if possible. Only public libraries available in Context7's database are supported, so small or private libraries may not be available. */
  libraryTitle: string
  /** Specific topic to focus on (e.g., "routing", "hooks", "authentication") */
