import { SiyaBridge } from './bridge/siya-bridge'
import { loadGatewayConfig } from './config/load-config'
import { startHealthServer } from './health-server'
import {
  startGatewayScheduler,
  stopGatewayScheduler,
} from './scheduler/gateway-runtime'
import { startTelegramBot } from './telegram/bot'

import type { AgentDefinition } from '@siya/sdk'
import type { Logger } from '@siya/common/types/contracts/logger'

export type StartGatewayOptions = {
  cwd?: string
  apiKey: string
  agentDefinitions?: AgentDefinition[]
  logger?: Logger
  /** foreground = standalone `siya gateway`; embedded = alongside main CLI */
  mode?: 'foreground' | 'embedded'
}

export type GatewayHandle = {
  stop: () => Promise<void>
}

export async function startGateway(
  options: StartGatewayOptions,
): Promise<GatewayHandle> {
  const cwd = options.cwd ?? process.cwd()
  const config = await loadGatewayConfig({ cwd, verbose: true })

  const telegram = config.channels.telegram
  if (!telegram?.enabled) {
    throw new Error(
      'Telegram channel is not enabled. Run `siya gateway setup` first.',
    )
  }

  if (!telegram.botToken) {
    throw new Error(
      'Telegram bot token missing. Set TELEGRAM_BOT_TOKEN or channels.telegram.botToken in gateway.json.',
    )
  }

  const projectCwd = telegram.cwd ? telegram.cwd : cwd
  const bridge = await SiyaBridge.create({
    apiKey: options.apiKey,
    cwd: projectCwd,
    telegramConfig: telegram,
    agentDefinitions: options.agentDefinitions,
    logger: options.logger,
  })

  const health = await startHealthServer(config.gateway.port)
  const bot = await startTelegramBot({
    token: telegram.botToken,
    config: telegram,
    bridge,
    projectCwd,
  })

  const mode = options.mode ?? 'foreground'
  const log = (message: string) => {
    if (mode === 'embedded') {
      options.logger?.info({}, message)
    } else {
      console.log(message)
    }
  }

  if (mode === 'foreground') {
    await startGatewayScheduler(bridge)
  }

  log(
    `Siya Telegram gateway started (agent=${telegram.defaultAgent}, cwd=${projectCwd}, bot=@${bot.botUsername ?? 'unknown'})`,
  )
  log(`Health: http://127.0.0.1:${config.gateway.port}/health`)
  if (mode === 'foreground') {
    console.log('Press Ctrl+C to stop.')
  }

  return {
    stop: async () => {
      await stopGatewayScheduler()
      await bot.stop()
      await health.close()
    },
  }
}

export async function getGatewayStatus(options?: {
  cwd?: string
}): Promise<{
  configured: boolean
  sourceFile?: string
  telegramEnabled: boolean
  hasToken: boolean
  defaultAgent?: string
  projectCwd?: string
}> {
  const config = await loadGatewayConfig({
    cwd: options?.cwd ?? process.cwd(),
    verbose: false,
  })

  const telegram = config.channels.telegram
  return {
    configured: Boolean(config._sourceFilePath),
    sourceFile: config._sourceFilePath || undefined,
    telegramEnabled: Boolean(telegram?.enabled),
    hasToken: Boolean(telegram?.botToken),
    defaultAgent: telegram?.defaultAgent,
    projectCwd: telegram?.cwd,
  }
}

import fs from 'fs'
import path from 'path'

import { InputFile } from 'grammy'

import { getOwnerUserId } from '../security/group-access'
import { chunkTelegramMessage } from './format'

import type { TelegramChannelConfig } from '@siya/common/types/gateway'
import type { Api } from 'grammy'

export type TelegramNotifyTarget = 'owner_dm' | 'current_chat'

type OutboundState = {
  api: Api | null
  config: TelegramChannelConfig | null
  ownerDmChatId: string | null
  lastActiveChatId: string | null
}

const state: OutboundState = {
  api: null,
  config: null,
  ownerDmChatId: null,
  lastActiveChatId: null,
}

export function registerTelegramOutbound(params: {
  api: Api
  config: TelegramChannelConfig
}): void {
  const ownerId = getOwnerUserId(params.config)
  state.api = params.api
  state.config = params.config
  state.ownerDmChatId = ownerId
}

export function setActiveTelegramChat(chatId: string): void {
  state.lastActiveChatId = chatId
}

export function unregisterTelegramOutbound(): void {
  state.api = null
  state.config = null
  state.ownerDmChatId = null
  state.lastActiveChatId = null
}

export function isTelegramOutboundReady(): boolean {
  return state.api !== null
}

function resolveChatId(params: {
  target?: TelegramNotifyTarget
  chatId?: string
}): string {
  if (!state.api) {
    throw new Error(
      'Telegram gateway is not running. Start `siya gateway` or launch Siya with auto-start enabled.',
    )
  }

  if (params.chatId?.trim()) {
    return params.chatId.trim()
  }

  const target = params.target ?? 'owner_dm'

  if (target === 'current_chat' && state.lastActiveChatId) {
    return state.lastActiveChatId
  }

  if (state.ownerDmChatId) {
    return state.ownerDmChatId
  }

  throw new Error(
    'No Telegram destination available. Message the bot once so it knows your chat ID.',
  )
}

export async function sendTelegramText(params: {
  message: string
  target?: TelegramNotifyTarget
  chatId?: string
}): Promise<{ chatId: string; messageCount: number }> {
  const api = state.api
  if (!api) {
    throw new Error('Telegram gateway is not running.')
  }

  const chatId = resolveChatId(params)
  const chunks = chunkTelegramMessage(params.message.trim())
  if (chunks.length === 0) {
    throw new Error('Message is empty.')
  }

  for (const chunk of chunks) {
    await api.sendMessage(chatId, chunk)
  }

  return { chatId, messageCount: chunks.length }
}

export async function sendTelegramDocument(params: {
  filePath: string
  caption?: string
  target?: TelegramNotifyTarget
  chatId?: string
}): Promise<{ chatId: string }> {
  const api = state.api
  if (!api) {
    throw new Error('Telegram gateway is not running.')
  }

  const absolutePath = path.resolve(params.filePath)
  if (!fs.existsSync(absolutePath)) {
    throw new Error(`File not found: ${absolutePath}`)
  }

  const chatId = resolveChatId(params)
  const isImage = absolutePath.match(/\.(png|jpe?g|gif|webp)$/i)

  if (isImage) {
    await api.sendPhoto(chatId, new InputFile(absolutePath), {
      caption: params.caption?.slice(0, 1024),
    })
  } else {
    await api.sendDocument(chatId, new InputFile(absolutePath), {
      caption: params.caption?.slice(0, 1024),
    })
  }

  return { chatId }
}

export function getTelegramOutboundDebugState(): {
  ready: boolean
  ownerDmChatId: string | null
  lastActiveChatId: string | null
} {
  return {
    ready: isTelegramOutboundReady(),
    ownerDmChatId: state.ownerDmChatId,
    lastActiveChatId: state.lastActiveChatId,
  }
}

