        dmPolicy: 'pairing',
        allowFrom: [`tg:${userId}`],
        ownerUserId: userId,
        groupPolicy: 'allowlist',
        groups: {
          '*': { requireMention: true, enabled: true },
        },
        mentionAliases: ['siya'],
        defaultAgent: agentId,
        cwd: path.resolve(projectCwd),
        streaming: 'partial',
      },
    },
    gateway: {
      port: 8787,
      logLevel: 'info',
    },
  })

  const configPath = await saveGatewayConfig(config, getConfigDir())

  console.log('\nConfiguration saved to:')
