  console.log('\nAdd to your environment (.env or shell profile):')
  console.log(`  TELEGRAM_BOT_TOKEN=${botToken}`)
  console.log(`  OPENROUTER_API_KEY=<your-key>`)
  console.log('\nThen start the gateway:')
  console.log('  siya gateway\n')

  return configPath
}

