import type {
  FilePart,
  ImagePart,
  ReasoningPart,
  TextPart,
  ToolCallPart,
  ToolResultOutput,
} from './content-part'
import type { ProviderMetadata } from './provider-metadata'

export type AuxiliaryMessageData = {
  providerOptions?: ProviderMetadata
  tags?: string[]

  /**
   * Unix timestamp (ms) when the message was added to history.
   * Used to detect prompt cache expiry (>5 min gap = cache miss).
   * This field is stripped before sending to the LLM.
   */
  sentAt?: number

  // James: All the below is overly prescriptive for the framework.
  // Instead, let's tag what the message is, and let the user decide time to live, keep during truncation, etc.
  /** @deprecated Use tags instead. */
  timeToLive?: 'agentStep' | 'userPrompt'
  /** @deprecated Use tags instead. */
  keepDuringTruncation?: boolean
  /** @deprecated Use tags instead. */
  keepLastTags?: string[]
}

export type SystemMessage = {
  role: 'system'
  content: TextPart[]
} & AuxiliaryMessageData

export type UserMessage = {
  role: 'user'
  content: (TextPart | ImagePart | FilePart)[]
} & AuxiliaryMessageData

export type AssistantMessage = {
  role: 'assistant'
  content: (TextPart | ReasoningPart | ToolCallPart)[]
} & AuxiliaryMessageData

export type ToolMessage = {
  role: 'tool'
  toolCallId: string
  toolName: string
  content: ToolResultOutput[]
} & AuxiliaryMessageData

export type Message =
  | SystemMessage
  | UserMessage
  | AssistantMessage
  | ToolMessage

const DURATION_PATTERN =
  /^(\d+(?:\.\d+)?)\s*(s|sec|secs|second|seconds|m|min|mins|minute|minutes|h|hr|hrs|hour|hours|d|day|days)$/i

const UNIT_TO_MS: Record<string, number> = {
  s: 1000,
  sec: 1000,
  secs: 1000,
  second: 1000,
  seconds: 1000,
  m: 60_000,
  min: 60_000,
  mins: 60_000,
  minute: 60_000,
  minutes: 60_000,
  h: 3_600_000,
  hr: 3_600_000,
  hrs: 3_600_000,
  hour: 3_600_000,
  hours: 3_600_000,
  d: 86_400_000,
  day: 86_400_000,
  days: 86_400_000,
}

export function parseDurationToMs(value: string): number {
  const trimmed = value.trim().toLowerCase()
  const match = trimmed.match(DURATION_PATTERN)
  if (!match) {
    throw new Error(
      `Invalid duration "${value}". Use formats like 30s, 5m, 2h, or 1d.`,
    )
  }

  const amount = Number(match[1])
  const unit = match[2].toLowerCase()
  const multiplier = UNIT_TO_MS[unit]
  if (!multiplier || !Number.isFinite(amount) || amount <= 0) {
    throw new Error(`Invalid duration "${value}".`)
  }

  return Math.round(amount * multiplier)
}

export function parseRunAt(value: string): number {
  const timestamp = Date.parse(value)
  if (!Number.isFinite(timestamp)) {
    throw new Error(
      `Invalid run_at "${value}". Use an ISO 8601 datetime like 2026-06-11T09:00:00+05:30.`,
    )
  }
  return timestamp
}

/**
 * Minimal cron support for common patterns (minute hour dom month dow).
 * Supports star wildcards, numbers, ranges, step values, and lists.
 */
export function getNextCronRun(expression: string, from = Date.now()): number {
  const parts = expression.trim().split(/\s+/)
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron "${expression}". Use 5 fields: minute hour day month weekday.`,
    )
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts
  const start = new Date(from)
  start.setSeconds(0, 0)
  start.setMinutes(start.getMinutes() + 1)

  for (let i = 0; i < 366 * 24 * 60; i++) {
    const candidate = new Date(start.getTime() + i * 60_000)
    if (
      matchesCronField(minuteExpr, candidate.getMinutes(), 0, 59) &&
      matchesCronField(hourExpr, candidate.getHours(), 0, 23) &&
      matchesCronField(domExpr, candidate.getDate(), 1, 31) &&
      matchesCronField(monthExpr, candidate.getMonth() + 1, 1, 12) &&
      matchesCronField(dowExpr, candidate.getDay(), 0, 6)
    ) {
      return candidate.getTime()
    }
  }

  throw new Error(`Could not find next run for cron "${expression}".`)
}

function matchesCronField(
  expr: string,
  value: number,
  min: number,
  max: number,
): boolean {
  if (expr === '*') {
    return true
  }

  return expr.split(',').some((part) => {
    const stepMatch = part.match(/^(.+)\/(\d+)$/)
    const base = stepMatch ? stepMatch[1] : part
    const step = stepMatch ? Number(stepMatch[2]) : 1

    if (base === '*') {
      return (value - min) % step === 0
    }

    if (base.includes('-')) {
      const [start, end] = base.split('-').map(Number)
      if (!Number.isFinite(start) || !Number.isFinite(end)) {
        return false
      }
      if (value < start || value > end) {
        return false
      }
      return (value - start) % step === 0
    }

    const exact = Number(base)
    return Number.isFinite(exact) && exact === value
  })
}

export function resolveNextRunAt(input: {
  runAt?: string
  delay?: string
  repeatInterval?: string
  cron?: string
  from?: number
}): { nextRunAt: number; scheduleKind: 'once' | 'recurring'; repeatIntervalMs?: number; cronExpression?: string } {
  const from = input.from ?? Date.now()
  const scheduleModes = [
    Boolean(input.runAt),
    Boolean(input.delay),
    Boolean(input.repeatInterval),
    Boolean(input.cron),
  ].filter(Boolean).length

  if (scheduleModes !== 1) {
    throw new Error(
      'Provide exactly one schedule: run_at, delay, repeat_interval, or cron.',
    )
  }

  if (input.runAt) {
    const nextRunAt = parseRunAt(input.runAt)
    if (nextRunAt <= from) {
      throw new Error('run_at must be in the future.')
    }
    return { nextRunAt, scheduleKind: 'once' }
  }

  if (input.delay) {
    const delayMs = parseDurationToMs(input.delay)
    return { nextRunAt: from + delayMs, scheduleKind: 'once' }
  }

  if (input.repeatInterval) {
    const repeatIntervalMs = parseDurationToMs(input.repeatInterval)
    return {
      nextRunAt: from + repeatIntervalMs,
      scheduleKind: 'recurring',
      repeatIntervalMs,
    }
  }

  if (input.cron) {
    const nextRunAt = getNextCronRun(input.cron, from)
    return {
      nextRunAt,
      scheduleKind: 'recurring',
      cronExpression: input.cron,
    }
  }

  throw new Error('No schedule provided.')
}

import fs from 'fs'
import fsPromises from 'fs/promises'
import path from 'path'

import { getConfigDir } from '../config/load-config'
import { safeJsonStringify } from '../util/safe-json'

import type { ScheduledTask } from './types'

type SchedulerStoreFile = {
  version: 1
  tasks: ScheduledTask[]
}

function getStorePath(): string {
  return path.join(getConfigDir(), 'scheduler', 'tasks.json')
}

function createEmptyStore(): SchedulerStoreFile {
  return { version: 1, tasks: [] }
}

export async function loadScheduledTasks(): Promise<ScheduledTask[]> {
  const filePath = getStorePath()
  try {
    const content = await fsPromises.readFile(filePath, 'utf8')
    const parsed = JSON.parse(content) as SchedulerStoreFile
    if (!parsed?.tasks || !Array.isArray(parsed.tasks)) {
      return []
    }
    return parsed.tasks
  } catch {
    return []
  }
}

export async function saveScheduledTasks(tasks: ScheduledTask[]): Promise<void> {
  const filePath = getStorePath()
  await fsPromises.mkdir(path.dirname(filePath), { recursive: true })
  const payload: SchedulerStoreFile = {
    version: 1,
    tasks,
  }
  await fsPromises.writeFile(
    filePath,
    `${safeJsonStringify(payload)}\n`,
    'utf8',
  )
}

export function loadScheduledTasksSync(): ScheduledTask[] {
  const filePath = getStorePath()
  if (!fs.existsSync(filePath)) {
    return []
  }
  try {
    const content = fs.readFileSync(filePath, 'utf8')
    const parsed = JSON.parse(content) as SchedulerStoreFile
    return Array.isArray(parsed?.tasks) ? parsed.tasks : []
  } catch {
    return []
  }
}

import { randomUUID } from 'crypto'

import { getNextCronRun } from './parse-schedule'
import { resolveNextRunAt } from './parse-schedule'
import { loadScheduledTasks, saveScheduledTasks } from './store'

import type {
  CreateScheduledTaskInput,
  ScheduledTask,
  ScheduledTaskRunner,
} from './types'

const TICK_INTERVAL_MS = 15_000

let runner: ScheduledTaskRunner | null = null
let tickTimer: ReturnType<typeof setInterval> | null = null
let isTicking = false
let started = false

export function registerScheduledTaskRunner(nextRunner: ScheduledTaskRunner): void {
  runner = nextRunner
}

export function unregisterScheduledTaskRunner(): void {
  runner = null
}

export function isSchedulerRunning(): boolean {
  return started
}

export async function startScheduler(): Promise<void> {
  if (started) {
    return
  }
  started = true
  await tickScheduler()
  tickTimer = setInterval(() => {
    void tickScheduler()
  }, TICK_INTERVAL_MS)
}

export async function stopScheduler(): Promise<void> {
  started = false
  if (tickTimer) {
    clearInterval(tickTimer)
    tickTimer = null
  }
}

export async function createScheduledTask(
  input: CreateScheduledTaskInput,
): Promise<ScheduledTask> {
  const now = Date.now()
  const schedule = resolveNextRunAt({
    runAt: input.runAt,
    delay: input.delay,
    repeatInterval: input.repeatInterval,
    cron: input.cron,
    from: now,
  })

  const task: ScheduledTask = {
    id: randomUUID(),
    label: input.label?.trim() || undefined,
    prompt: input.prompt.trim(),
    taskType: input.taskType ?? 'agent_task',
    scheduleKind: schedule.scheduleKind,
    nextRunAt: schedule.nextRunAt,
    repeatIntervalMs: schedule.repeatIntervalMs,
    cronExpression: schedule.cronExpression,
    agentId: input.agentId?.trim() || undefined,
    notifyTelegram: input.notifyTelegram,
    status: 'pending',
    createdAt: now,
    updatedAt: now,
    runCount: 0,
    maxRuns: input.maxRuns,
    source: input.source,
    metadata: input.metadata,
  }

  const tasks = await loadScheduledTasks()
  tasks.push(task)
  await saveScheduledTasks(tasks)
  return task
}

export async function listScheduledTasks(options?: {
  includeCompleted?: boolean
}): Promise<ScheduledTask[]> {
  const tasks = await loadScheduledTasks()
  if (options?.includeCompleted) {
    return tasks.sort((a, b) => a.nextRunAt - b.nextRunAt)
  }
  return tasks
    .filter((task) => task.status === 'pending' || task.status === 'running')
    .sort((a, b) => a.nextRunAt - b.nextRunAt)
}

export async function cancelScheduledTask(taskId: string): Promise<ScheduledTask | null> {
  const tasks = await loadScheduledTasks()
  const index = tasks.findIndex((task) => task.id === taskId)
  if (index === -1) {
    return null
  }

  const task = tasks[index]
  if (task.status === 'cancelled' || task.status === 'completed') {
    return task
  }

  const updated: ScheduledTask = {
    ...task,
    status: 'cancelled',
    updatedAt: Date.now(),
  }
  tasks[index] = updated
  await saveScheduledTasks(tasks)
  return updated
}

async function tickScheduler(): Promise<void> {
  if (isTicking || !runner) {
    return
  }

  isTicking = true
  try {
    const now = Date.now()
    const tasks = await loadScheduledTasks()
    let changed = false

    for (const task of tasks) {
      if (task.status !== 'pending') {
        continue
      }
      if (task.nextRunAt > now) {
        continue
      }

      const index = tasks.findIndex((entry) => entry.id === task.id)
      if (index === -1) {
        continue
      }

      tasks[index] = {
        ...task,
        status: 'running',
        updatedAt: now,
      }
      changed = true
      await saveScheduledTasks(tasks)

      try {
        const result = await runner(task)
        await markTaskAfterRun(task.id, {
          success: true,
          summary: result.summary,
        })
      } catch (error) {
        await markTaskAfterRun(task.id, {
          success: false,
          summary: error instanceof Error ? error.message : String(error),
        })
      }
    }

    if (changed) {
      await saveScheduledTasks(await loadScheduledTasks())
    }
  } finally {
    isTicking = false
  }
}

async function markTaskAfterRun(
  taskId: string,
  result: { success: boolean; summary?: string },
): Promise<void> {
  const tasks = await loadScheduledTasks()
  const index = tasks.findIndex((task) => task.id === taskId)
  if (index === -1) {
    return
  }

  const task = tasks[index]
  const now = Date.now()
  const nextRunCount = task.runCount + 1
  const reachedMaxRuns =
    typeof task.maxRuns === 'number' && nextRunCount >= task.maxRuns

  if (
    task.scheduleKind === 'recurring' &&
    !reachedMaxRuns &&
    (task.repeatIntervalMs || task.cronExpression)
  ) {
    const nextRunAt = task.cronExpression
      ? getNextCronRun(task.cronExpression, now)
      : now + (task.repeatIntervalMs ?? 0)

    tasks[index] = {
      ...task,
      status: 'pending',
      nextRunAt,
      lastRunAt: now,
      lastRunResult: result.summary,
      runCount: nextRunCount,
      updatedAt: now,
    }
  } else {
    tasks[index] = {
      ...task,
      status: result.success ? 'completed' : 'failed',
      lastRunAt: now,
      lastRunResult: result.summary,
      runCount: nextRunCount,
      updatedAt: now,
    }
  }

  await saveScheduledTasks(tasks)
}

import { runScheduledTaskWithTelegramNotify } from '../tools/schedule-tools'

import {
  registerScheduledTaskRunner,
  startScheduler,
  stopScheduler,
  unregisterScheduledTaskRunner,
} from './engine'

import type { SiyaBridge } from '../bridge/siya-bridge'

let gatewaySchedulerStarted = false

export async function startGatewayScheduler(
  bridge: SiyaBridge,
  defaultAgentId: string,
): Promise<void> {
  if (gatewaySchedulerStarted) {
    return
  }

  registerScheduledTaskRunner(async (task) => {
    if (task.taskType === 'reminder') {
      return runScheduledTaskWithTelegramNotify(task, async () => ({
        summary: task.prompt,
      }))
    }

    const chatId = task.metadata?.telegram_chat_id ?? 'scheduled-task'
    const agentId = task.agentId ?? defaultAgentId
    const result = await bridge.processMessage({
      chatId,
      text: `[Scheduled task${task.label ? `: ${task.label}` : ''}] ${task.prompt}`,
      agentId,
    })

    return runScheduledTaskWithTelegramNotify(task, async () => ({
      summary: result.reply,
    }))
  })

  await startScheduler()
  gatewaySchedulerStarted = true
}

export async function stopGatewayScheduler(): Promise<void> {
  if (!gatewaySchedulerStarted) {
    return
  }
  await stopScheduler()
  unregisterScheduledTaskRunner()
  gatewaySchedulerStarted = false
}

