+import fs from 'fs'
+import fsPromises from 'fs/promises'
+import path from 'path'
+
+import { getConfigDir } from '../config/load-config'
+import { safeJsonStringify } from '../util/safe-json'
+
+import type { ScheduledTask } from './types'
+
+type SchedulerStoreFile = {
+  version: 1
+  tasks: ScheduledTask[]
+}
+
+function getStorePath(): string {
+  return path.join(getConfigDir(), 'scheduler', 'tasks.json')
+}
+
+function getWalPath(): string {
+  return path.join(getConfigDir(), 'scheduler', 'tasks.json.wal')
+}
+
+function createEmptyStore(): SchedulerStoreFile {
+  return { version: 1, tasks: [] }
+}
+
+/**
+ * Write data to a file atomically by writing to a temp file first, then renaming.
+ * This prevents partial writes from corrupting the file on crash.
+ */
+async function atomicWriteJson(filePath: string, data: SchedulerStoreFile): Promise<void> {
+  const dir = path.dirname(filePath)
+  await fsPromises.mkdir(dir, { recursive: true })
+  const tmpPath = `${filePath}.tmp`
+  await fsPromises.writeFile(tmpPath, `${safeJsonStringify(data)}\n`, 'utf8')
+  await fsPromises.rename(tmpPath, filePath)
+}
+
+/**
+ * Read and parse a JSON store file. Returns null if the file doesn't exist or is invalid.
+ */
+function readStoreFile(filePath: string): SchedulerStoreFile | null {
+  try {
+    const content = fs.readFileSync(filePath, 'utf8')
+    const parsed = JSON.parse(content) as SchedulerStoreFile
+    if (parsed?.version === 1 && Array.isArray(parsed.tasks)) {
+      return parsed
+    }
+    return null
+  } catch {
+    return null
+  }
+}
+
+/**
+ * Delete a file silently if it exists.
+ */
+async function safeUnlink(filePath: string): Promise<void> {
+  try {
+    await fsPromises.unlink(filePath)
+  } catch {
+    // Ignore — file may not exist
+  }
+}
+
+export async function loadScheduledTasks(): Promise<ScheduledTask[]> {
+  const walPath = getWalPath()
+
+  // WAL recovery: if a WAL file exists, it contains the most recent valid state
+  // (it was written before the main store). Use it and persist to main store.
+  const walStore = readStoreFile(walPath)
+  if (walStore) {
+    await atomicWriteJson(getStorePath(), walStore)
+    await safeUnlink(walPath)
+    return walStore.tasks
+  }
+
+  // Normal path: load from main store
+  const mainStore = readStoreFile(getStorePath())
+  return mainStore?.tasks ?? []
+}
+
+export async function saveScheduledTasks(tasks: ScheduledTask[]): Promise<void> {
+  const payload: SchedulerStoreFile = { version: 1, tasks }
+
+  // Step 1: Write to WAL first (crash-safe recovery point)
+  await atomicWriteJson(getWalPath(), payload)
+
+  // Step 2: Write to main store
+  await atomicWriteJson(getStorePath(), payload)
+
+  // Step 3: WAL is no longer needed — safe to delete
+  await safeUnlink(getWalPath())
+}
+
+export function loadScheduledTasksSync(): ScheduledTask[] {
+  const walPath = getWalPath()
+
+  // WAL recovery
+  const walStore = readStoreFile(walPath)
+  if (walStore) {
+    // Synchronous recovery: write main store and delete WAL
+    try {
+      const dir = path.dirname(getStorePath())
+      fs.mkdirSync(dir, { recursive: true })
+      fs.writeFileSync(getStorePath(), `${safeJsonStringify(walStore)}\n`, 'utf8')
+      fs.unlinkSync(walPath)
+    } catch {
+      // Best-effort — WAL data is still valid
+    }
+    return walStore.tasks
+  }
+
+  const mainStore = readStoreFile(getStorePath())
+  return mainStore?.tasks ?? []
+}

